import React, { useEffect, useState } from 'react';
import axios from 'axios';

const TimbangMuat = () => {
  const [rfid, setRfid] = useState(null);
  const [truck, setTruck] = useState(null);
  const [form, setForm] = useState({
    itemType: '',
    quantity: '',
    bruto: '',
    tara: '',
    netto: 0
  });

  // Fungsi ambil RFID
  const fetchRFID = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/rfid/latest');
      if (res.data.truck) {
        setRfid(res.data.truck.truckId);
        setTruck(res.data.truck);
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Polling RFID tiap 2 detik
  useEffect(() => {
    const interval = setInterval(() => {
      if (!rfid) { // hanya polling kalau belum ada RFID
        fetchRFID();
      }
    }, 2000);

    return () => clearInterval(interval); // bersihkan interval saat komponen unmount
  }, [rfid]);

  // Kalkulasi netto otomatis
  useEffect(() => {
    const bruto = parseFloat(form.bruto) || 0;
    const tara = parseFloat(form.tara) || 0;
    setForm(prev => ({ ...prev, netto: bruto - tara }));
  }, [form.bruto, form.tara]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      truckId: rfid,
      ...form
    };

    try {
      await axios.post('http://localhost:5000/api/loadings', payload);
      alert("Data timbang muat berhasil disimpan!");

      // Reset semua state supaya kembali menunggu RFID baru
      setForm({ itemType: '', quantity: '', bruto: '', tara: '', netto: 0 });
      setTruck(null);
      setRfid(null);
    } catch (err) {
      console.error(err);
      alert("Gagal menyimpan data timbang muat");
    }
  };

  return (
    <div className="p-8">
      <h1 className="text-2xl font-bold mb-4">Timbang Muat</h1>

      {!truck ? (
        <p>Menunggu scan RFID...</p>
      ) : (
        <>
          <div className="bg-gray-100 p-4 mb-6 rounded">
            <h2 className="font-semibold mb-2">Data Truk</h2>
            <p><strong>Truck ID:</strong> {truck.truckId}</p>
            <p><strong>Driver:</strong> {truck.driver}</p>
            <p><strong>Tipe Truck:</strong> {truck.truckType}</p>
            <p><strong>Tanggal:</strong> {truck.date?.split('T')[0]}</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label>Jenis Barang:</label>
              <input type="text" name="itemType" value={form.itemType} onChange={handleChange} className="border p-2 w-full" required />
            </div>

            <div>
              <label>Jumlah Barang:</label>
              <input type="number" name="quantity" value={form.quantity} onChange={handleChange} className="border p-2 w-full" required />
            </div>

            <div>
              <label>Bruto (kg):</label>
              <input type="number" name="bruto" value={form.bruto} onChange={handleChange} className="border p-2 w-full" required />
            </div>

            <div>
              <label>Tara (kg):</label>
              <input type="number" name="tara" value={form.tara} onChange={handleChange} className="border p-2 w-full" required />
            </div>

            <div>
              <label>Netto (kg):</label>
              <input type="number" name="netto" value={form.netto} readOnly className="border p-2 w-full bg-gray-200" />
            </div>

            <button type="submit" className="bg-blue-500 text-white px-4 py-2 rounded">
              Simpan
            </button>
          </form>
        </>
      )}
    </div>
  );
};

export default TimbangMuat;
